hooks.command:
python3 -c "
import sys, json, re, subprocess, os

try:
    data = json.load(sys.stdin)
except:
    sys.exit(0)

command = data.get('tool_input', {}).get('command', '')
if 'git commit' not in command:
    sys.exit(0)

try:
    result = subprocess.run(
        ['git', 'diff', '--cached', '--name-only'],
        capture_output=True, text=True, timeout=10
    )
    staged_files = result.stdout.strip().splitlines()
except:
    sys.exit(0)

pending_staged = [f for f in staged_files if f.endswith('sophia-pending-changes.md')]
if not pending_staged:
    sys.exit(0)

rel_path = pending_staged[0]

try:
    with open(rel_path, 'r', encoding='utf-8', errors='replace') as f:
        content = f.read()
except:
    sys.exit(0)

# Find the Quick Stats line
qs_match = re.search(r'\*\*Quick Stats:\*\*\s*`(.+?)`', content)
if not qs_match:
    sys.exit(0)

qs_raw = qs_match.group(1)

# Parse Quick Stats values
def parse_qs(raw):
    result = {}
    for part in raw.split('|'):
        part = part.strip()
        m = re.match(r'^(.+?):\s*(\d+)$', part)
        if m:
            key = m.group(1).strip()
            result[key] = int(m.group(2))
    return result

qs = parse_qs(qs_raw)

# Count data rows in table blocks.
# A data row: starts with |, is not a header row (contains column names), not a divider row (|---|)
def is_header_row(line):
    # Header rows contain column name keywords
    lower = line.lower()
    return any(kw in lower for kw in ['| # |', '| status |', '| triage |', '| meaning |', '| tier |', '| rating |', '| scale |'])

def is_divider_row(line):
    return bool(re.match(r'^\|[-| ]+\|', line))

def is_data_row(line):
    if not line.startswith('|'):
        return False
    if is_header_row(line):
        return False
    if is_divider_row(line):
        return False
    return True

lines = content.splitlines()

# Identify section boundaries by ## Section N headers
section_starts = {}
for i, line in enumerate(lines):
    m = re.match(r'^## Section (\d+)', line)
    if m:
        section_starts[int(m.group(1))] = i

# Build section line ranges
all_section_nums = sorted(section_starts.keys())
section_ranges = {}
for idx, sec_num in enumerate(all_section_nums):
    start = section_starts[sec_num]
    end = section_starts[all_section_nums[idx + 1]] if idx + 1 < len(all_section_nums) else len(lines)
    section_ranges[sec_num] = (start, end)

def count_data_rows_in_range(start, end):
    count = 0
    for i in range(start, end):
        if is_data_row(lines[i]):
            count += 1
    return count

# Count per section
actual = {}
actual['Active'] = count_data_rows_in_range(*section_ranges.get(1, (0, 0)))
actual['Deferred Named'] = count_data_rows_in_range(*section_ranges.get(2, (0, 0)))
actual['Deferred No Home'] = count_data_rows_in_range(*section_ranges.get(3, (0, 0)))
actual['Notes & Objectives'] = count_data_rows_in_range(*section_ranges.get(4, (0, 0)))
actual['Pending AAR'] = count_data_rows_in_range(*section_ranges.get(5, (0, 0)))
actual['Behavioral Standards Active'] = count_data_rows_in_range(*section_ranges.get(6, (0, 0)))

# Complete checkmark count: data rows in any section where Status cell contains 'Complete' and checkmark
complete_count = 0
for sec_num, (start, end) in section_ranges.items():
    for i in range(start, end):
        line = lines[i]
        if is_data_row(line):
            if 'Complete' in line and '\u2713' in line:
                complete_count += 1
actual['Complete \u2713 (pending transfer)'] = complete_count

# Compare
mismatches = []
for key in ['Active', 'Deferred Named', 'Deferred No Home', 'Notes & Objectives', 'Pending AAR', 'Behavioral Standards Active', 'Complete \u2713 (pending transfer)']:
    qs_val = qs.get(key, None)
    act_val = actual.get(key, 0)
    if qs_val is None:
        continue
    if qs_val != act_val:
        mismatches.append((key, qs_val, act_val))

if mismatches:
    print('')
    print('QUICK STATS GATE -- COMMIT BLOCKED')
    print('Quick Stats numbers do not match actual row counts.')
    print('')
    print('  {:<35} {:<12} {}'.format('SECTION', 'STATS SAYS', 'ACTUAL'))
    print('  ' + '-' * 60)
    for key in ['Active', 'Deferred Named', 'Deferred No Home', 'Notes & Objectives', 'Pending AAR', 'Behavioral Standards Active', 'Complete \u2713 (pending transfer)']:
        qs_val = qs.get(key, 0)
        act_val = actual.get(key, 0)
        flag = '<- MISMATCH' if qs_val != act_val else '\u2713'
        print('  {:<35} {:<12} {}  {}'.format(key, str(qs_val), str(act_val), flag))
    print('')
    print('FIX: Update Quick Stats line to match actual counts, then re-commit.')
    print('')
    sys.exit(1)

sys.exit(0)
"
